import boto3
import json
import logging
from PIL import Image
import io
from botocore.exceptions import ClientError

# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Initialize boto3 clients
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

# SNS Topic ARN - should be passed as environment variable
SNS_TOPIC_ARN = "arn:aws:sns:us-east-1:123456789012:image-processing-topic"

def lambda_handler(event, context):
    try:
        # Validate input
        if 'Records' not in event:
            raise ValueError("Invalid event structure")
        
        # Process each S3 event record
        for record in event['Records']:
            # Extract bucket and key from S3 event
            bucket = record['s3']['bucket']['name']
            key = record['s3']['object']['key']
            
            # Validate key (prevent path traversal)
            if '..' in key or key.startswith('/'):
                logger.warning(f"Invalid key detected: {key}")
                continue
                
            logger.info(f"Processing image from bucket: {bucket}, key: {key}")
            
            # Read image from S3
            response = s3_client.get_object(Bucket=bucket, Key=key)
            image_content = response['Body'].read()
            
            # Process image (example: resize)
            processed_image = process_image(image_content)
            
            # Generate output key
            output_key = f"processed/{key}"
            
            # Save processed image back to S3
            s3_client.put_object(
                Bucket=bucket,
                Key=output_key,
                Body=processed_image,
                ContentType='image/jpeg'
            )
            
            # Send notification via SNS
            sns_client.publish(
                TopicArn=SNS_TOPIC_ARN,
                Message=json.dumps({
                    'bucket': bucket,
                    'input_key': key,
                    'output_key': output_key,
                    'status': 'success'
                }),
                Subject='Image Processing Complete'
            )
            
            logger.info(f"Successfully processed and saved: {output_key}")
            
    except ClientError as e:
        error_code = e.response['Error']['Code']
        logger.error(f"Client error: {error_code}")
        # Send error notification
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Message=json.dumps({
                'error': str(e),
                'status': 'error'
            }),
            Subject='Image Processing Error'
        )
        raise e
    except Exception as e:
        logger.error(f"Unexpected error: {str(e)}")
        # Send error notification
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Message=json.dumps({
                'error': str(e),
                'status': 'error'
            }),
            Subject='Image Processing Error'
        )
        raise e

def process_image(image_content):
    """Process image - example implementation"""
    try:
        # Open image with PIL
        image = Image.open(io.BytesIO(image_content))
        
        # Resize image (example)
        image = image.resize((800, 600))
        
        # Save processed image to bytes
        output = io.BytesIO()
        image.save(output, format='JPEG', quality=85)
        output.seek(0)
        
        return output.getvalue()
    except Exception as e:
        logger.error(f"Error processing image: {str(e)}")
        raise e

